package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithQuote_withValidChar() {
        CSVFormat original = CSVFormat.DEFAULT;
        Character quoteChar = '\'';
        CSVFormat updated = original.withQuote(quoteChar);

        assertNotNull(updated);
        assertNotSame(original, updated);
        assertEquals(quoteChar, updated.getQuoteCharacter());
    }

    @Test
    void testWithQuote_withDoubleQuoteChar() {
        CSVFormat original = CSVFormat.DEFAULT;
        Character quoteChar = '"';
        CSVFormat updated = original.withQuote(quoteChar);

        assertNotNull(updated);
        assertNotSame(original, updated);
        assertEquals(quoteChar, updated.getQuoteCharacter());
    }

    @Test
    void testWithQuote_withBackslashChar() {
        CSVFormat original = CSVFormat.DEFAULT;
        Character quoteChar = '\\';
        CSVFormat updated = original.withQuote(quoteChar);

        assertNotNull(updated);
        assertNotSame(original, updated);
        assertEquals(quoteChar, updated.getQuoteCharacter());
    }

    @Test
    void testWithQuote_withNullChar() {
        CSVFormat original = CSVFormat.DEFAULT;
        Character quoteChar = '\0';
        CSVFormat updated = original.withQuote(quoteChar);

        assertNotNull(updated);
        assertNotSame(original, updated);
        assertEquals(quoteChar, updated.getQuoteCharacter());
    }
}
